// kernel.cl
typedef struct {
    double energy;
    double total_xs;
    double elastic_xs;
    double absorbtion_xs;
    double fission_xs;
    double nu_fission_xs;
} NuclideGridPoint;

typedef struct {
    int nthreads;
    long n_isotopes;
    long n_gridpoints;
    int lookups;
    char HM;
    int grid_type; 
    int hash_bins;
    int particles;
    int simulation_method;
    int binary_mode;
    int kernel_id;
    double p_energy_samples[1000000];
    int mat_samples[1000000];
} Inputs;

__kernel void macro_xs_lookup_kernel(__global Inputs * in, int max_num_nucs, __global int * num_nucs, __global double * concs, __global double * unionized_energy_array, __global int * index_grid, __global NuclideGridPoint * nuclide_grids, __global int * mats, __global int * verification)
{
    int i = get_global_id(0);

    if (i >= in->lookups)
        return;

    double macro_xs_vector[5] = {0};

    double p_energy = in->p_energy_samples[i];
    int mat = in->mat_samples[i];

    long idx = -1;

    if (in->grid_type == 0) { // UNIONIZED
        idx = 0; // This is a placeholder, you need to implement the actual logic for UNIONIZED
    } else if (in->grid_type == 1) { // NUCLIDE
        idx = 0; // This is a placeholder, you need to implement the actual logic for NUCLIDE
    } else if (in->grid_type == 2) { // HASH
        idx = 0; // This is a placeholder, you need to implement the actual logic for HASH
    }

    for (int j = 0; j < num_nucs[mat]; j++) {
        double xs_vector[5];
        int p_nuc = mats[mat * max_num_nucs + j];
        double conc = concs[mat * max_num_nucs + j];

        // Calculate micro XS
        NuclideGridPoint low, high;
        low.energy = nuclide_grids[p_nuc * in->n_gridpoints].energy;
        high.energy = nuclide_grids[p_nuc * in->n_gridpoints + 1].energy;

        double f = (high.energy - p_energy) / (high.energy - low.energy);

        xs_vector[0] = high.total_xs - f * (high.total_xs - low.total_xs);
        xs_vector[1] = high.elastic_xs - f * (high.elastic_xs - low.elastic_xs);
        xs_vector[2] = high.absorbtion_xs - f * (high.absorbtion_xs - low.absorbtion_xs);
        xs_vector[3] = high.fission_xs - f * (high.fission_xs - low.fission_xs);
        xs_vector[4] = high.nu_fission_xs - f * (high.nu_fission_xs - low.nu_fission_xs);

        for (int k = 0; k < 5; k++)
            macro_xs_vector[k] += xs_vector[k] * conc;
    }

    double max = -1.0;
    int max_idx = 0;
    for (int j = 0; j < 5; j++) {
        if (macro_xs_vector[j] > max) {
            max = macro_xs_vector[j];
            max_idx = j;
        }
    }
    verification[i] = max_idx + 1;
}
